async function n(e){const t=await fetch(`${e}`,{credentials:"include"});if(!t.ok)throw new Error(`HTTP ${t.status}: ${t.statusText}`);return t.json()}async function r(e,t){const s=await fetch(`${e}`,{method:"POST",headers:{"Content-Type":"application/json"},credentials:"include",body:JSON.stringify(t)});if(!s.ok){const a=await s.text().catch(()=>"");throw new Error(`HTTP ${s.status}: ${a||s.statusText}`)}return s.json()}async function o(){return n("/health")}async function c(){return n("/version")}async function i(){return n("/v1/agents")}async function u(e){return r("/v1/chat",e)}async function f(){return n("/v1/federation/status")}async function d(){return n("/v1/federation/nodes")}async function g(){return n("/v1/plugins")}export{c as a,i as b,g as c,f as d,d as e,o as g,u as s};
